import { NextRequest, NextResponse } from 'next/server'

export function middleware(request: NextRequest) {
  const { method, nextUrl: url } = request
  const start = Date.now()

  const methodColored = method === 'GET' ? '\x1b[32m' : method === 'POST' ? '\x1b[33m' : '\x1b[36m'
  const reset = '\x1b[0m'

  console.log(
    `[${new Date().toISOString()}] ${methodColored}${method}${reset} ${url.pathname}${url.search ? url.search : ''}`,
  )

  const response = NextResponse.next()

  response.headers.set('x-request-timing', `${Date.now() - start}ms`)

  console.log(
    `[${new Date().toISOString()}] → ${response.status} (${Date.now() - start}ms)`,
  )

  return response
}

export const config = {
  matcher: [
    /*
     * Match all request paths except for:
     * - _next/static (static files)
     * - _next/image (image optimization files)
     * - favicon.ico (favicon file)
     * - images, manifest, and other public files (e.g. robots.txt)
     */
    '/((?!_next/static|_next/image|favicon.ico|.*\\.(?:svg|png|jpg|jpeg|gif|webp)$).*)',
  ],
}

import { NextRequest, NextResponse } from 'next/server'

export function proxy(request: NextRequest) {
  const { method, nextUrl: url } = request
  const start = Date.now()

  const methodColored =
    method === 'GET' ? '\x1b[32m' : method === 'POST' ? '\x1b[33m' : '\x1b[36m'
  const reset = '\x1b[0m'

  console.log(
    `[${new Date().toISOString()}] ${methodColored}${method}${reset} ${url.pathname}${url.search ? url.search : ''}`,
  )

  const response = NextResponse.next()

  console.log(
    `[${new Date().toISOString()}] → ${response.status} (${Date.now() - start}ms)`,
  )

  return response
}

export const config = {
  matcher: [
    /*
     * Match all request paths except:
     * - _next/static (static files)
     * - _next/image (image optimization)
     * - favicon.ico
     * - static images (svg, png, jpg, gif, webp)
     */
    '/((?!_next/static|_next/image|favicon.ico|.*\\.(?:svg|png|jpg|jpeg|gif|webp)$).*)',
  ],
}
